      "content": "export class CsvParser {
  private delimiter: string;

  constructor(options?: { delimiter?: string }) {
    this.delimiter = options?.delimiter ?? ',';
  }

  public parse(text: string): Record<string, string>[] {
    const lines = text.split('\n');
    const rows: Record<string, string>[] = [];
    let headers: string[] = [];
    for (const line of lines) {
      if (line.trim() === '') continue;
      const cells = this.splitCsvLine(line);
      if (headers.length === 0) {
        headers = cells;
      } else {
        const row: Record<string, string> = {};
        for (let i = 0; i < headers.length; i++) {
          row[headers[i]] = cells[i] ?? '';
        }
        rows.push(row);
      }
    }
    return rows;
  }

  public stringify(rows: Record<string, string>[]): string {
    if (rows.length === 0) return '';
    const headers = Object.keys(rows[0]);
    const lines: string[] = [];
    const headerLine = headers.map(h => this.escapeCsvCell(h)).join(this.delimiter);
    lines.push(headerLine);
    for (const row of rows) {
      const line = headers.map(h => this.escapeCsvCell(row[h])).join(this.delimiter);
      lines.push(line);
    }
    return lines.join('\n');
  }

  private splitCsvLine(line: string): string[] {
    const cells: string[] = [];
    let cell = '';
    let inQuotes = false;
    for (let i = 0; i < line.length; i++) {
      const ch = line[i];
      if (ch === '"') {
        if (inQuotes && i + 1 < line.length && line[i + 1] === '"') {
          cell += '"';
          i++;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (ch === this.delimiter && !inQuotes) {
        cells.push(cell);
        cell = '';
      } else {
        cell += ch;
      }
    }
    cells.push(cell);
    return cells;
  }

  private escapeCsvCell(cell: string): string {
    if (cell.includes('"') || cell.includes(',') || cell.includes('\n')) {
      const escaped = cell.replace(/"/g, '""');
      return '"' + escaped + '"';
    }
    return cell;
  }
}

export class CsvFilter {
  private rows: Record<string, string>[];
  private columns: string[];

  constructor(rows: Record<string, string>[]) {
    this.rows = rows;
    this.columns = rows.length > 0 ? Object.keys(rows[0]) : [];
  }

  public where(predicate: (row: Record<string, string>) => boolean): Record<string, string>[] {
    return this.rows.filter(predicate);
  }

  public select(columns: string[]): Record<string, string>[] {
    const selected = columns.map(c => c.trim());
    return this.rows.map(row => {
      const newRow: Record<string, string> = {};
      for (const col of selected) {
        if (col in row) {
          newRow[col] = row[col];
        }
      }
      return newRow;
    });
  }

  public sortBy(column: string): Record<string, string>[] {
    const col = column.trim();
    const sorted = this.rows.slice();
    sorted.sort((a, b) => {
      const aVal = a[col] ?? '';
      const bVal = b[col] ?? '';
      return aVal.localeCompare(bVal);
    });
    return sorted;
  }

  public count(): number {
    return this.rows.length;
  }
}
